ode[below=.5ex of pd2] (pd3) {$(X_3, M_{X_3})$}; \draw[->] (graph) to[out=50, in=180] (pd1.west); \draw[->] (graph) to[out=0, in=180] (pd2.west); \draw[->] (graph) to[out=-50, in=180] (pd3.west); 
ode[fill=tLightPeach, right=of pd1, rounded corners=2.5pt, draw, thick] (mt1) {MST 1}; 
ode[fill=tLightPeach, right=of pd2, rounded corners=2.5pt, draw, thick] (mt2) {MST 2}; 
ode[fill=tLightPeach, right=of pd3, rounded corners=2.5pt, draw, thick] (mt3) {MST 3}; 
ode[right=of mt1] (r1) {$R_1$}; 
ode[right=of mt2] (r2) {$R_2$}; 
ode[right=of mt3] (r3) {$R_3$}; 
ode[right=of r2] (rep) {$	ext{Concat}(R_1, R_2, R_3)$}; 
ode[fill=tLightPeach,right=of rep, rounded corners=2.5pt, draw, thick] (fc) {FC}; 
ode[right=of fc](y){$Y$}; \draw (pd1) edge (mt1); \draw[opacity=1] (pd2) -- (mt2); \draw[opacity=1] (pd3) -- (mt3); \draw[->] (r1) to[out=0, in=130] ($(rep.west)-(-1pt, -3pt)$); \draw[->] (r2) to[out=0, in=180] (rep.west); \draw[->] (r3) to[out=0, in=-130] ($(rep.west)-(-1pt, 3pt)$); \draw[opacity=1] (mt1) -- (r1); \draw[opacity=1] (mt2) -- (r2); \draw[opacity=1] (mt3) -- (r3); \draw (rep) -- (fc); \draw (fc) -- (y); \end{tikzpicture} \caption{Graph classification architecture. Given a graph \( G \), it's encoded into various ordinary or extended PDs, i.e., \( (X_i, M_{X_i}) \). Here, we have \(i \in \{1,2,3\}\) as demonstration. In experimentation, we can have \(i \in \{1,2,\ldots, n\}\) for some finite integer \(n\). Each diagram is processed by an independent instance of the Multiset Transformer (MST \( i \)), yielding its representation \( R_i \). These representations are concatenated to form the complete feature set of the graph. The classifier, represented by a fully connected layer (FC), then makes predictions based on this comprehensive representation.}\label{fig:pdmst}

